package main

import "fmt"

type Player struct {
    Name    string
    Health  int
    MaxHealth int
    Attack  int
    Defense int
}

// ---- Pointer receiver modifies the struct ----
func (p *Player) TakeDamage(damage int) {
    actualDamage := damage - p.Defense/2
    if actualDamage > 0 {
        p.Health -= actualDamage
        if p.Health < 0 {
            p.Health = 0
        }
    }
}

func (p *Player) Heal(amount int) {
    p.Health += amount
    if p.Health > p.MaxHealth {
        p.Health = p.MaxHealth
    }
}

func (p *Player) SetName(name string) {
    p.Name = name
}

// ---- Value receiver for read-only ----
func (p Player) IsAlive() bool {
    return p.Health > 0
}

func (p Player) Display() {
    fmt.Printf("%s (HP: %d/%d, ATK: %d, DEF: %d)\n",
        p.Name, p.Health, p.MaxHealth, p.Attack, p.Defense)
}

func main() {
    // ---- Pointer receiver vs value receiver ----
    hero := Player{
        Name:    "Hero",
        Health:  100,
        MaxHealth: 100,
        Attack:  20,
        Defense: 10,
    }

    fmt.Println("Initial:")
    hero.Display()

    // ---- Pointer receiver modifies ----
    hero.TakeDamage(30)
    hero.Heal(20)
    hero.SetName("Aragorn")

    fmt.Println("\nAfter modifications:")
    hero.Display()

    // ---- Value receiver doesn't modify ----
    fmt.Printf("\nIs alive? %t\n", hero.IsAlive())

    // ---- Pointer receiver with nil ----
    // var p *Player
    // p.TakeDamage(10)  // Panic!

    // ---- Pointer receiver with pointer ----
    p := &hero
    p.TakeDamage(20)
    fmt.Println("\nAfter pointer method:")
    hero.Display()

    // ---- Pointer receiver with auto-dereference ----
    // Go automatically dereferences pointers for methods
    // p.TakeDamage(10) is the same as (*p).TakeDamage(10)

    // ---- When to use pointer receivers ----
    // 1. Modifying the struct
    // 2. Large structs (avoids copying)
    // 3. Consistency (all methods use pointer)
    // 4. Nil receivers

    // ---- When to use value receivers ----
    // 1. Read-only operations
    // 2. Small structs (copy is cheap)
    // 3. Immutable data
}

