package main

import "fmt"

type Enemy struct {
    Name   string
    Health int
    Attack int
}

func (e *Enemy) TakeDamage(d int) {
    e.Health -= d
    if e.Health < 0 {
        e.Health = 0
    }
    fmt.Printf("%s took %d damage! Health: %d\n", e.Name, d, e.Health)
}

func (e Enemy) IsAlive() bool {
    return e.Health > 0
}

func main() {
    goblin := Enemy{Name: "Goblin", Health: 30, Attack: 8}

    goblin.TakeDamage(10)
    goblin.TakeDamage(25)

    if goblin.IsAlive() {
        fmt.Println("Goblin is still alive!")
    } else {
        fmt.Println("Goblin is defeated!")
    }
}
